package com.sismptm.partner.data.remote
import retrofit2.Response import retrofit2.http.Body import retrofit2.http.POST
interface ApiService {
/** POST /api/partners/register/partner */ @POST("api/partners/register/partner") suspend fun registerPartner(@Body request: RegisterPartnerRequest): Response<RegisterPartnerResponse> }
// ── Request DTO (espeja RegisterPartnerRequest del backend) ────────────────── data class RegisterPartnerRequest( val email: String, val password: String, val name: String, val areaId: Int, val termsAccepted: Boolean, val language: String, // "en" | "es" val picDirectory: String? = null )
// ── Response DTO (espeja RegisterPartnerResponse del backend) ───────────────── data class RegisterPartnerResponse( val id: Long, val email: String, val name: String, val status: String, val language: String, val createdAt: String, val termsAccepted: Boolean, val picDirectory: String?, val role: String, val areaId: Int, val availabilityStatus: String )

package com.sismptm.partner.data.remote
import retrofit2.Response import retrofit2.http.Body import retrofit2.http.GET import retrofit2.http.POST
interface ApiService {
/** GET /ping */ @GET("ping") suspend fun ping(): Response<PingResponse>
/** POST /api/partners/register/partner */ @POST("api/partners/register/partner") suspend fun registerPartner(@Body request: RegisterPartnerRequest): Response<RegisterPartnerResponse>
/** POST /api/partners/location/update */ @POST("api/partners/location/update") suspend fun updateLocation(@Body request: LocationUpdateRequest): Response<Unit> }
data class PingResponse( val status: String )
// ── Request DTO (espeja RegisterPartnerRequest del backend) ────────────────── data class RegisterPartnerRequest( val email: String, val password: String, val name: String, val areaId: Int, val termsAccepted: Boolean, val language: String, // "en" | "es" val picDirectory: String? = null )
// ── Response DTO (espeja RegisterPartnerResponse del backend) ───────────────── data class RegisterPartnerResponse( val id: Long, val email: String, val name: String, val status: String, val language: String, val createdAt: String, val termsAccepted: Boolean, val picDirectory: String?, val role: String, val areaId: Int, val availabilityStatus: String )
data class LocationUpdateRequest( val latitude: Double, val longitude: Double )

package com.sismptm.partner.ui.navigation

import androidx.compose.runtime.Composable
import androidx.navigation.compose.NavHost
import androidx.navigation.compose.composable
import androidx.navigation.compose.rememberNavController
import com.sismptm.partner.ui.screens.HomeScreen
import com.sismptm.partner.ui.screens.LoginScreen
import com.sismptm.partner.ui.screens.RegisterScreen
import com.sismptm.partner.ui.screens.RequestDetailScreen
import com.sismptm.partner.ui.screens.ServiceDetailScreen

/**
 * Sealed class representing all navigation routes in the mobile-partner application.
 * Each object corresponds to a screen in the partner navigation graph.
 */
sealed class Screen(val route: String) {
    object Login : Screen("login")
    object Register : Screen("register")
    object Home : Screen("home")
    object SolicitudDetail : Screen("solicitud_detail")
    object ServicioDetail : Screen("servicio_detail")
}

/**
 * Main navigation graph composable for the mobile-partner application.
 * Defines the navigation structure and relationships between all screens.
 * Manages the NavController and handles navigation between Login, Register, Home,
 * SolicitudDetail, and ServicioDetail screens.
 */
@Composable
fun PartnerNavGraph() {
    val navController = rememberNavController()

    NavHost(
        navController = navController,
        startDestination = Screen.Login.route
    ) {
        composable(Screen.Login.route) {
            LoginScreen(
                onLoginSuccess = {
                    navController.navigate(Screen.Home.route) {
                        popUpTo(Screen.Login.route) { inclusive = true }
                    }
                },
                onNavigateToRegister = {
                    navController.navigate(Screen.Register.route)
                }
            )
        }
        composable(Screen.Register.route) {
            RegisterScreen(
                onRegisterSuccess = {
                    navController.navigate(Screen.Home.route) {
                        popUpTo(Screen.Login.route) { inclusive = true }
                    }
                },
                onNavigateToLogin = {
                    navController.popBackStack()
                }
            )
        }
        composable(Screen.Home.route) {
            HomeScreen(
                onLogout = {
                    navController.navigate(Screen.Login.route) {
                        popUpTo(Screen.Home.route) { inclusive = true }
                    }
                },
                onRequestTour = {
                    navController.navigate(Screen.SolicitudDetail.route)
                }
            )
        }

        composable(Screen.SolicitudDetail.route) {
            RequestDetailScreen(
                onAccept = { navController.navigate(Screen.ServicioDetail.route) },
                onReject = { navController.popBackStack() },
                onBack = { navController.popBackStack() }
            )
        }

        composable(Screen.ServicioDetail.route) {
            ServiceDetailScreen(
                onComplete = { navController.popBackStack() },
                onBack = { navController.popBackStack() }
            )
        }
    }
}

